parameters.text:
=Create a comprehensive lead enrichment profile for: {{ $json.company }}

Domain: {{ $json.domain }}

COMPANY SEARCH RESULTS:
{{ $json.company_info }}

RECENT NEWS SEARCH RESULTS:
{{ $json.recent_news }}

KEY PEOPLE SEARCH RESULTS:
{{ $json.key_people }}

Synthesize all search results into a structured lead profile. Respond ONLY with valid JSON.

parameters.jsCode:
const items = $input.all();
const output = items[0].json.output;

let parsed;
try {
  parsed = JSON.parse(output);
} catch (e) {
  const jsonMatch = output.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (jsonMatch) {
    try { parsed = JSON.parse(jsonMatch[1].trim()); } catch (e2) { parsed = null; }
  }
  if (!parsed) {
    const objMatch = output.match(/\{[\s\S]*\}/);
    if (objMatch) {
      try { parsed = JSON.parse(objMatch[0]); } catch (e3) { parsed = null; }
    }
  }
}

if (!parsed) {
  return [{ json: { parse_status: 'failed', error: 'Could not parse lead profile from AI response', raw_output: output } }];
}

// Flatten for Google Sheets
return [{
  json: {
    parse_status: 'success',
    timestamp: new Date().toISOString(),
    company_name: parsed.company_name || '',
    domain: parsed.domain || '',
    tagline: parsed.tagline || '',
    industry: parsed.industry || '',
    sub_industry: parsed.sub_industry || '',
    founded: parsed.founded || '',
    headquarters: parsed.headquarters || '',
    company_size: parsed.company_size || '',
    funding_stage: parsed.funding_stage || '',
    estimated_revenue: parsed.estimated_revenue || '',
    products_services: Array.isArray(parsed.products_services) ? parsed.products_services.join(', ') : '',
    tech_stack: Array.isArray(parsed.tech_stack_signals) ? parsed.tech_stack_signals.join(', ') : '',
    key_people: Array.isArray(parsed.key_people) ? parsed.key_people.map(p => p.name + ' (' + p.title + ')').join(', ') : '',
    recent_news: Array.isArray(parsed.recent_news) ? parsed.recent_news.map(n => n.headline).join(' | ') : '',
    pain_points: Array.isArray(parsed.pain_points) ? parsed.pain_points.join(', ') : '',
    outreach_angle_1: parsed.outreach_angles?.[0]?.angle || '',
    opening_line_1: parsed.outreach_angles?.[0]?.opening_line || '',
    outreach_angle_2: parsed.outreach_angles?.[1]?.angle || '',
    opening_line_2: parsed.outreach_angles?.[1]?.opening_line || '',
    icp_fit_score: parsed.icp_fit_score || '',
    enrichment_confidence: parsed.enrichment_confidence || '',
    data_gaps: Array.isArray(parsed.data_gaps) ? parsed.data_gaps.join(', ') : '',
    full_profile_json: JSON.stringify(parsed)
  }
}];

